window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["dmv-motorcycle"] = window.COURSE_LANG["dmv-motorcycle"] || {};
window.COURSE_LANG["dmv-motorcycle"]["es"] = [
  {"id":1,"q":"Un casco de motocicleta para uso en vía pública debe cumplir con qué norma de seguridad?","opts":["DOT FMVSS 218","EPA Sección 608","No se exige ninguna norma","OSHA 1910"],"re":"California exige un casco que cumpla con la norma federal de seguridad DOT FMVSS 218."},
  {"id":2,"q":"En California, quién debe usar casco en una motocicleta?","opts":["Solo el conductor","Solo los menores de 18 años","Tanto el conductor como el pasajero, en todo momento","Nadie — es opcional"],"re":"La ley universal de cascos de California (CVC 27803) exige un casco DOT para el conductor y el pasajero siempre que la motocicleta esté en movimiento."},
  {"id":3,"q":"Como la motocicleta no protege tus ojos, debes usar:","opts":["Nada — entrecerrar los ojos contra el viento","Una careta (visor) o gafas protectoras","Lentes de sol solo de noche","Un solo lente de contacto"],"re":"Una careta o gafas protegen del viento, el polvo, los insectos y los escombros; un parabrisas pequeño por sí solo no basta."},
  {"id":4,"q":"La chaqueta y el pantalón de conducción más protectores están hechos de:","opts":["Pantalón corto y camiseta","Nylon delgado y suelto","Cuero resistente o sintético resistente a la abrasión que cubra brazos y piernas","Una camiseta sin mangas"],"re":"La cobertura total en cuero o sintético reforzado protege contra la abrasión en una caída."},
  {"id":5,"q":"El mejor color de ropa para ser visto por otros conductores es:","opts":["Negro","Gris oscuro","Colores brillantes o reflectantes como naranja o amarillo","Verde oscuro"],"re":"La ropa brillante y reflectante hace que otros conductores te noten con mucha más facilidad."},
  {"id":6,"q":"Los guantes adecuados para motocicleta son:","opts":["Sin dedos","De dedos completos y de cuero u otro material duradero","Mitones de lana","Innecesarios en verano"],"re":"Los guantes duraderos de dedos completos mejoran el agarre y protegen las manos en una caída."},
  {"id":7,"q":"El mejor calzado para conducir es:","opts":["Sandalias","Tenis bajos","Botas resistentes que cubran el tobillo","Pies descalzos"],"re":"Las botas por encima del tobillo protegen los pies y los tobillos y ayudan a evitar quemaduras con partes calientes."},
  {"id":8,"q":"T-CLOCS se refiere a:","opts":["Un tipo de casco","Una lista de inspección previa al viaje: Llantas, Controles, Luces, Aceite, Chasis, Soportes","Una multa de tránsito","Una marca de llanta"],"re":"T-CLOCS es la inspección estándar previa al viaje: llantas/ruedas, controles, luces, aceite/fluidos, chasis y soportes."},
  {"id":9,"q":"El freno delantero se acciona con:","opts":["La palanca de la mano izquierda","La palanca de la mano derecha","El pedal del pie izquierdo","El pedal del pie derecho"],"re":"La palanca de la mano derecha acciona el freno delantero; el pedal del pie derecho acciona el freno trasero."},
  {"id":10,"q":"El freno trasero se acciona con:","opts":["La palanca de la mano derecha","El pedal del pie derecho","La palanca de la mano izquierda","El embrague"],"re":"El pedal del pie derecho controla el freno trasero."},
  {"id":11,"q":"El embrague se acciona con:","opts":["La palanca de la mano izquierda","La palanca de la mano derecha","El pedal del pie derecho","El acelerador"],"re":"La palanca de la mano izquierda es el embrague; la palanca del pie izquierdo cambia las marchas."},
  {"id":12,"q":"El acelerador es:","opts":["El puño izquierdo","El puño derecho — gíralo hacia ti para acelerar","Un pedal","Lo mismo que el embrague"],"re":"El puño derecho es el acelerador; girarlo hacia ti aumenta la velocidad del motor."},
  {"id":13,"q":"Para la mejor capacidad de frenado, debes:","opts":["Usar solo el freno trasero","Usar solo el freno delantero","Usar ambos frenos cada vez que reduces o te detienes","Arrastrar los pies por el suelo"],"re":"Usar ambos frenos juntos da la detención más corta y controlada."},
  {"id":14,"q":"Aproximadamente cuánta capacidad de frenado puede aportar el freno delantero?","opts":["Cerca del 10%","Cerca del 25%","Cerca del 70% — la mayoría","Nada"],"re":"El freno delantero aporta cerca del 70% de la capacidad de frenado porque el peso se desplaza hacia adelante al frenar."},
  {"id":15,"q":"La rutina de arranque FINE-C significa:","opts":["Nada en particular","Combustible (Fuel), Ignición, Neutral, interruptor de apagado del motor (Engine cut-off), Estárter/Embrague (Choke/Clutch)","Una marca de llanta","Cuatro direccionales"],"re":"FINE-C: combustible abierto, ignición encendida, neutral, interruptor de apagado en marcha, estárter/embrague según se necesite."},
  {"id":16,"q":"Para subir a una marcha más alta debes:","opts":["Acelerar y soltar el embrague únicamente","Soltar el acelerador, apretar el embrague, levantar la palanca de cambios y luego soltar el embrague","Aplicar el freno delantero","Apagar y encender la llave"],"re":"Un cambio ascendente suave coordina el acelerador, la palanca del embrague y la palanca de cambios del pie."},
  {"id":17,"q":"Cuántas posiciones útiles ofrece generalmente un solo carril a un motociclista?","opts":["Una","Dos","Tres — la porción izquierda, central y derecha","Seis"],"re":"Un carril tiene tres posiciones útiles; elige la que maximice tu visibilidad y tu colchón de espacio."},
  {"id":18,"q":"Cuál posición del carril es la mejor en toda situación?","opts":["La porción izquierda","La porción central","Ninguna — no hay una sola mejor; cámbiala según las condiciones","La porción derecha"],"re":"Ninguna posición es la mejor en todas las situaciones; cambia de posición para ser visto y evitar peligros."},
  {"id":19,"q":"La porción central de un carril a veces acumula:","opts":["Nada en absoluto","Una franja de aceite y grasa y escombros","Tracción adicional","Reflectores"],"re":"El goteo de aceite y los escombros pueden acumularse en la franja central; evítala cuando esté resbaladiza."},
  {"id":20,"q":"Lo más importante que puedes hacer para evitar un choque es:","opts":["Ir tan rápido como el tráfico","Hacerte visible y mantener un colchón de espacio a tu alrededor","Conducir en los puntos ciegos de otros conductores","Seguir de cerca"],"re":"Ser visto y mantener espacio a tu alrededor previene la mayoría de los conflictos antes de que comiencen."},
  {"id":21,"q":"La estrategia SEE para manejar el riesgo significa:","opts":["Stop, Exit, Escape (Detener, Salir, Escapar)","Search, Evaluate, Execute (Buscar, Evaluar, Ejecutar)","Speed, Engine, Exhaust (Velocidad, Motor, Escape)","See, Eat, Enjoy (Ver, Comer, Disfrutar)"],"re":"Busca los peligros, Evalúa cómo podrían afectarte y luego Ejecuta la acción correcta."},
  {"id":22,"q":"Antes de cambiar de carril debes revisar el tráfico:","opts":["Usando solo los espejos","Girando la cabeza para revisar el punto ciego además de usar los espejos","Tocando la bocina","Cerrando los ojos un momento"],"re":"Los espejos tienen puntos ciegos; siempre gira la cabeza para mirar antes de moverte."},
  {"id":23,"q":"En condiciones normales debes mantener una distancia de seguimiento de al menos:","opts":["Medio segundo","2 segundos","Ninguna distancia en particular","Exactamente 10 largos de auto"],"re":"Mantén al menos 2 segundos de distancia de seguimiento, y auméntala en malas condiciones."},
  {"id":24,"q":"En una intersección, el mayor peligro para un motociclista suele ser:","opts":["Un auto estacionado","Un auto que viene de frente y gira a la izquierda cruzando tu camino","Un peatón en la acera","El semáforo en sí"],"re":"Los autos que vienen de frente y giran a la izquierda delante de una motocicleta causan la mayoría de los choques con varios vehículos."},
  {"id":25,"q":"Conducir en el punto ciego de otro conductor es:","opts":["Una buena idea","Peligroso, porque puede que no sepan que estás ahí","Obligatorio por ley","Más seguro de noche"],"re":"Si un conductor no puede verte, puede meterse en tu camino; conduce donde te puedan ver."},
  {"id":26,"q":"La forma correcta de tomar una curva es:","opts":["Frenar fuerte a la mitad de la curva","Reducir antes de la curva, mirar a través de ella, presionar y acelerar","Acelerar al entrar en ella","Pasar en punto muerto con el embrague apretado"],"re":"Reducir, Mirar, Presionar, Acelerar: fija tu velocidad de entrada antes de la curva y luego acelera suavemente a través de ella."},
  {"id":27,"q":"Para girar a velocidad, el contramanillar (countersteering) significa:","opts":["Girar el manillar en sentido contrario a la curva","Presionar el puño del lado al que quieres ir — presiona a la derecha para ir a la derecha","Inclinarte en sentido contrario a la moto","Usar solo los frenos"],"re":"A velocidad, presiona el puño en la dirección hacia la que quieres inclinarte e ir."},
  {"id":28,"q":"Al reducir o detenerte, debes:","opts":["Mirar hacia abajo a la rueda delantera","Mantener la cabeza y los ojos en alto, mirando hacia adelante","Apretar el embrague y mirar los indicadores","Cerrar el acelerador y mirarte los pies"],"re":"Mirar arriba y adelante, hacia donde quieres ir, mantiene la motocicleta estable y equilibrada."},
  {"id":29,"q":"Para detenerte rápidamente debes:","opts":["Usar solo el freno trasero","Aplicar ambos frenos con firmeza sin bloquear ninguna rueda","Tumbar la motocicleta","Usar solo el freno delantero"],"re":"Aprieta ambos frenos con firmeza y de forma progresiva, evitando bloquear una rueda."},
  {"id":30,"q":"Si debes detenerte estando en una curva, lo mejor es:","opts":["Frenar fuerte totalmente inclinado","Enderezar la motocicleta lo más posible y luego frenar","Tomar solo el freno delantero","Poner ambos pies en el suelo"],"re":"Una llanta inclinada tiene menos agarre para frenar, así que endereza primero si puedes y luego frena."},
  {"id":31,"q":"Si la rueda delantera se bloquea al frenar, debes:","opts":["Mantenerla bloqueada","Soltar el freno delantero y luego volver a aplicarlo suavemente","Aplicar aún más freno delantero","Soltar el manillar"],"re":"Suelta brevemente para recuperar la tracción de rodadura y luego vuelve a aplicar el freno con suavidad."},
  {"id":32,"q":"Reducir de marcha mientras frenas:","opts":["Nunca debe hacerse","Permite que el motor ayude a frenar y te deja en la marcha correcta para acelerar","Daña el motor","Es lo mismo que poner punto muerto"],"re":"Reducir de marcha aporta freno de motor y te deja listo para acelerar y salir de un peligro."},
  {"id":33,"q":"Mirar a través de una curva significa:","opts":["Fijar la vista en el guardabarros delantero","Girar la cabeza y mirar hacia donde quieres terminar","Observar el velocímetro","Cerrar los ojos en el vértice"],"re":"La motocicleta tiende a ir hacia donde miras, así que mira hacia la salida de la curva."},
  {"id":34,"q":"El mejor momento para fijar tu velocidad para una curva es:","opts":["Después de haber entrado en ella","Antes de entrar en ella","Justo en el vértice","No es necesario ajustar la velocidad"],"re":"Ajusta la velocidad antes de la curva para poder acelerar suavemente durante toda ella."},
  {"id":35,"q":"Un pavimento suele estar más resbaladizo:","opts":["Tras varias horas de lluvia intensa","Justo cuando empieza a llover, antes de que el aceite se lave","Cuando está completamente seco","Dentro de un túnel"],"re":"La lluvia ligera se mezcla con el aceite y el polvo y hace la superficie más resbaladiza justo cuando empieza a llover."},
  {"id":36,"q":"En un camino mojado, el mejor lugar para conducir es:","opts":["Sobre las líneas pintadas del carril","En las huellas de las llantas que dejan otros vehículos","Sobre tapas y placas de metal","Sobre el acotamiento de grava"],"re":"Las huellas de las llantas suelen tener más tracción; evita la pintura resbaladiza, las franjas de aceite y las superficies metálicas."},
  {"id":37,"q":"Para cruzar una superficie resbaladiza como hojas mojadas o grava, debes:","opts":["Frenar fuerte sobre la superficie","Reducir la velocidad antes de llegar y evitar frenar o girar de golpe","Acelerar fuerte para cruzarla","Pararte de pie sobre el asiento"],"re":"Reduce la velocidad de antemano y mantén tus acciones suaves para que las llantas conserven el agarre."},
  {"id":38,"q":"Al cruzar rejillas de metal o ranuras de lluvia que hacen serpentear la moto, debes:","opts":["Resistirte y frenar fuerte","Relajarte, mantener una velocidad constante y cruzar derecho","Hacer zigzag bruscamente","Detenerte encima de la rejilla"],"re":"La sensación de serpenteo es normal; mantente relajado y conserva tu trayectoria — asusta más de lo que es peligroso."},
  {"id":39,"q":"Para llevar un pasajero con seguridad, el pasajero debe:","opts":["Pararse sobre los estribos","Sentarse en un asiento adecuado con estribos, sujetarse y mantener ambos pies en los estribos incluso detenido","Sentarse delante del conductor","Inclinarse en sentido contrario al conductor en las curvas"],"re":"Un pasajero necesita asiento y estribos, debe sujetarse con firmeza, inclinarse con el conductor y mantener los pies en los estribos en todo momento."},
  {"id":40,"q":"La carga que se lleva en una motocicleta debe:","opts":["Ir alta y atada flojamente","Mantenerse baja, sujetarse con firmeza y colocarse sobre o delante del eje trasero","Colgarse del manillar","Sostenerse con una mano"],"re":"Una carga baja, segura y bien equilibrada sobre o delante del eje trasero mantiene estable el manejo."},
  {"id":41,"q":"Al conducir de noche debes:","opts":["Ir más rápido para llegar antes","Reducir la velocidad, usar la luz alta cuando puedas y aumentar la distancia de seguimiento","Apagar el faro para ahorrar batería","Seguir de cerca para ver con sus luces"],"re":"Menos luz significa menos tiempo para reaccionar, así que reduce la velocidad y date más espacio."},
  {"id":42,"q":"Si un perro corre hacia tu motocicleta, lo mejor es:","opts":["Patearlo","Acercarte despacio y luego acelerar para alejarte al llegar a él","Detenerte y esperar a que se vaya","Desviarte al carril de al lado"],"re":"Ajusta tu velocidad para poder acelerar y pasar al animal una vez que sepas hacia dónde va."},
  {"id":43,"q":"Si tu motocicleta empieza a tambalearse (wobble) a velocidad, debes:","opts":["Frenar fuerte de inmediato","Acelerar fuerte para salir del tambaleo","Soltar el acelerador gradualmente, sujetar con firmeza y no frenar fuerte","Soltar el manillar"],"re":"Cerrar el acelerador lentamente y sujetar con firmeza calma el tambaleo; frenar fuerte puede empeorarlo."},
  {"id":44,"q":"Al conducir en grupo por un camino recto, la formación recomendada es:","opts":["Lado a lado, de dos en dos","Escalonada","Apiñados muy juntos","Repartidos en dos carriles"],"re":"Una formación escalonada conserva los colchones de espacio; pasa a fila india en curvas, vueltas y malas condiciones."},
  {"id":45,"q":"En California, circular entre carriles (lane splitting) es:","opts":["Siempre ilegal","Legal cuando se hace de manera segura y prudente","Legal solo de noche","Legal solo en autopistas a más de 50 mph"],"re":"La ley de California (CVC 21658.1) permite circular entre carriles cuando se hace de forma segura y prudente."},
  {"id":46,"q":"Una licencia Clase M1 de California te permite operar:","opts":["Solo un ciclomotor","Cualquier motocicleta de dos ruedas (y también cubre las bicicletas motorizadas)","Solo autos de pasajeros","Tractocamiones"],"re":"La M1 cubre motocicletas y motociclos, y también permite todo lo que autoriza una M2."},
  {"id":47,"q":"Una licencia Clase M2 de California te permite operar:","opts":["Cualquier motocicleta","Solo una bicicleta motorizada o ciclomotor","Tractocamiones","Autobuses"],"re":"La M2 se limita a bicicletas motorizadas y ciclomotores."},
  {"id":48,"q":"El faro de una motocicleta debe estar:","opts":["Apagado durante el día","Encendido siempre que conduces — las motocicletas más nuevas lo encienden automáticamente","Usado solo de noche","Opcional con buen clima"],"re":"Conducir con el faro encendido mejora mucho cómo te ven los demás; las motocicletas modernas lo encienden automáticamente."},
  {"id":49,"q":"Para un conductor de 21 años o más, es ilegal operar una motocicleta con una concentración de alcohol en sangre (BAC) de:","opts":["0.08% o más","0.15% o más","0.20% o más","Cualquier cantidad está permitida"],"re":"El límite para adultos es 0.08%; los conductores menores de 21 enfrentan un límite casi nulo de 0.01%."},
  {"id":50,"q":"Antes de rebasar o cambiar de carril debes:","opts":["Simplemente avanzar cuando el camino se ve despejado","Señalar, revisar los espejos y girar la cabeza para revisar el punto ciego","Solo tocar la bocina","Acelerar sin señalar"],"re":"Señala tu intención, revisa los espejos y gira la cabeza para revisar el punto ciego antes de moverte."}
];
